--
-- Table structure for table `car_units`
--

DROP TABLE IF EXISTS `car_units`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `car_units` (
  `unit_id` int(11) NOT NULL AUTO_INCREMENT,
  `car_id` int(11) NOT NULL,
  `state_id` int(11) NOT NULL,
  `plate_number` varchar(50) NOT NULL,
  `color` varchar(80) NOT NULL,
  `current_status` enum('available','booked','maintenance','inactive') NOT NULL DEFAULT 'available',
  `reserved_booking_id` int(11) DEFAULT NULL,
  `mileage` int(11) NOT NULL DEFAULT 0,
  `last_service_date` date DEFAULT NULL,
  PRIMARY KEY (`unit_id`),
  UNIQUE KEY `plate_number` (`plate_number`),
  KEY `car_id` (`car_id`),
  KEY `idx_car_units_state_status_car` (`state_id`,`current_status`,`car_id`),
  KEY `idx_car_units_status` (`car_id`,`state_id`,`current_status`),
  KEY `idx_car_units_reserved_booking` (`reserved_booking_id`),
  CONSTRAINT `car_units_ibfk_1` FOREIGN KEY (`car_id`) REFERENCES `cars` (`car_id`) ON DELETE CASCADE,
  CONSTRAINT `car_units_ibfk_2` FOREIGN KEY (`state_id`) REFERENCES `rental_states` (`state_id`),
  CONSTRAINT `fk_car_units_reserved_booking` FOREIGN KEY (`reserved_booking_id`) REFERENCES `bookings` (`booking_id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=248 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

