DROP TABLE IF EXISTS `cars`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `cars` (
  `id` int(11) DEFAULT NULL,
  `car_id` int(11) NOT NULL AUTO_INCREMENT,
  `brand_id` int(11) NOT NULL DEFAULT 1,
  `category_id` int(11) NOT NULL DEFAULT 1,
  `car_name` varchar(120) NOT NULL,
  `brand` varchar(80) DEFAULT NULL,
  `model` varchar(120) NOT NULL DEFAULT '',
  `year` int(11) NOT NULL DEFAULT 2026,
  `type` varchar(80) NOT NULL DEFAULT '',
  `price_per_day` decimal(10,2) NOT NULL,
  `price_per_hour` decimal(10,2) NOT NULL DEFAULT 0.00,
  `engine` varchar(120) NOT NULL DEFAULT '',
  `horsepower` varchar(80) NOT NULL DEFAULT '',
  `acceleration_0_100` varchar(80) DEFAULT NULL,
  `torque` varchar(80) NOT NULL DEFAULT '',
  `transmission` varchar(80) NOT NULL DEFAULT '',
  `drivetrain` varchar(80) NOT NULL DEFAULT '',
  `fuel_type` varchar(80) NOT NULL DEFAULT '',
  `fuel_consumption` varchar(80) NOT NULL DEFAULT '',
  `front_brake` varchar(160) DEFAULT NULL,
  `rear_brake` varchar(160) DEFAULT NULL,
  `suspension` varchar(180) DEFAULT NULL,
  `seats` int(11) NOT NULL DEFAULT 5,
  `doors` int(11) NOT NULL DEFAULT 4,
  `luggage_capacity` varchar(80) NOT NULL DEFAULT '',
  `air_conditioning` enum('Yes','No') NOT NULL DEFAULT 'Yes',
  `safety_features` text DEFAULT NULL,
  `comfort_features` text DEFAULT NULL,
  `entertainment_features` text DEFAULT NULL,
  `description` text DEFAULT NULL,
  `specification` text DEFAULT NULL,
  `main_image` varchar(700) NOT NULL DEFAULT '',
  `image_url` varchar(700) DEFAULT NULL,
  `is_featured` tinyint(1) NOT NULL DEFAULT 0,
  `status` enum('active','inactive') NOT NULL DEFAULT 'active',
  `availability` tinyint(1) NOT NULL DEFAULT 1,
  `stock_quantity` int(11) NOT NULL DEFAULT 0,
  `is_deleted` tinyint(1) NOT NULL DEFAULT 0,
  `sort_order` int(11) NOT NULL DEFAULT 0,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `car_tag` varchar(80) DEFAULT NULL,
  PRIMARY KEY (`car_id`),
  KEY `brand_id` (`brand_id`),
  KEY `category_id` (`category_id`),
  CONSTRAINT `cars_ibfk_1` FOREIGN KEY (`brand_id`) REFERENCES `brands` (`brand_id`),
  CONSTRAINT `cars_ibfk_2` FOREIGN KEY (`category_id`) REFERENCES `categories` (`category_id`)
) ENGINE=InnoDB AUTO_INCREMENT=248 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

