--
-- Table structure for table `cart_items`
--

DROP TABLE IF EXISTS `cart_items`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `cart_items` (
  `cart_item_id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL,
  `car_id` int(11) NOT NULL,
  `unit_id` int(11) DEFAULT NULL,
  `pickup_state_id` int(11) NOT NULL,
  `pickup_location` int(11) NOT NULL,
  `dropoff_location` int(11) NOT NULL,
  `start_datetime` datetime NOT NULL,
  `end_datetime` datetime NOT NULL,
  `rental_days` int(11) NOT NULL DEFAULT 1,
  `price_per_day` decimal(10,2) NOT NULL DEFAULT 0.00,
  `subtotal` decimal(10,2) NOT NULL DEFAULT 0.00,
  `status` enum('active','unavailable','removed','checked_out') NOT NULL DEFAULT 'active',
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT NULL ON UPDATE current_timestamp(),
  `fuel_option` enum('none','prepaid_fuel') NOT NULL DEFAULT 'none',
  `fuel_charge` decimal(10,2) NOT NULL DEFAULT 0.00,
  PRIMARY KEY (`cart_item_id`),
  KEY `idx_cart_user` (`user_id`),
  KEY `idx_cart_car` (`car_id`),
  KEY `idx_cart_unit_time` (`unit_id`,`start_datetime`,`end_datetime`),
  KEY `idx_cart_status` (`status`),
  KEY `fk_cart_pickup_state` (`pickup_state_id`),
  CONSTRAINT `fk_cart_car` FOREIGN KEY (`car_id`) REFERENCES `cars` (`car_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_cart_pickup_state` FOREIGN KEY (`pickup_state_id`) REFERENCES `rental_states` (`state_id`) ON DELETE CASCADE ON UPDATE CASCADE,
  CONSTRAINT `fk_cart_unit` FOREIGN KEY (`unit_id`) REFERENCES `car_units` (`unit_id`) ON DELETE SET NULL ON UPDATE CASCADE,
  CONSTRAINT `fk_cart_user` FOREIGN KEY (`user_id`) REFERENCES `users` (`user_id`) ON DELETE CASCADE ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=12 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `cart_items`
--

