INSERT INTO `homepage_faq` VALUES (1,'How do I book a car?','Select your pickup state, pickup location, drop-off location, pickup date, pickup time, return date and return time. Then search available cars and continue the booking process.',1,1),(2,'Can I browse cars without selecting a date?','Yes. You can browse the catalogue first, but availability checking requires rental date and time.',2,1),(3,'Why do I need to select pickup state?','The pickup state helps the system show cars that are available under Johor, Melaka or Kuala Lumpur.',3,1),(4,'How does car availability work?','The system checks the selected state and rental period to decide which cars can be shown as available.',4,1),(5,'What happens if the car becomes unavailable in my cart?','You will need to choose another available car or change your rental date and time.',5,1),(6,'Can I compare cars before booking?','Yes. You can compare selected cars before deciding which car is more suitable.',6,1),(7,'How does Find Car Smart recommend cars?','Find Car Smart uses your selected needs such as budget, car type, seats, state and rental time to suggest suitable cars.',7,1),(8,'What happens after payment?','After payment, your booking status will wait for admin approval before it is confirmed.',8,1),(9,'Why is my booking waiting for admin approval?','Admin approval is required to verify booking details, car availability and payment information.',9,1),(10,'Can I cancel my booking?','Cancellation depends on the booking status. You can check the booking page for available actions.',10,1),(11,'Can I change my pickup or return time?','You may need to contact admin or create a new booking if the time change affects car availability.',11,1),(12,'Where can I view my booking status?','After login, open your profile or my bookings page to view booking status and progress.',12,1);
/*!40000 ALTER TABLE `homepage_faq` ENABLE KEYS */;
UNLOCK TABLES;

